    ['Out of the Depths'] = {
        id = 75,
        start_npc = 'Ayame',
        start_zone = 'Metalworks',
        start_pos = 'K-7',
        description = 'A Goblin lair known as Movalpolos has suddenly appeared in North Gustaberg. Ayame wishes you to investigate this lair with the cooperation of a visiting scholar waiting in Port Bastok.',
        reward = '1,200 to 2,200 gil',
        fame = 'Bastok',
        fame_level = '3',
        title = 'Trash Collector',
        repeatable = nil,
        previous = nil,
        next = {'A Question of Faith'},
        requirements = {
            {name = 'Hoary Bomb Ash', count = 11},
        },
        walkthrough = '1. Talk to Ayame for a starting cut-scene, agree twice to start the quest.\n2. Go to Port Bastok and talk with Ravorara (E-7) outside the Steaming Sheep Restaurant for a cutscene.\n3. Go to Oldton Movalpolos and talk to Brakobrik (K-10).\n   - Closest warp is via Proto-Waypoint to the Geomagnetic Fount at (K-11) if you have it.\n4. Kill Ancient Bombs in Oldton Movalpolos to get Hoary Bomb Ash. At least 1 ash will always drop from a bomb, with up to 3 dropping with Treasure Hunter. Obtain 11 bomb ash in total.\n5. Trade between 1 to 4 Hoary Bomb Ash to Brakobrik at (K-11) to receive 4 different key items. You can only have one of each key item; trading the same amount of ashes twice will just waste the ashes. He\'ll offer you the following key items in exchange for the ash:\n   - Trade 1 ash for the [Key Item] Dusty tome - (100 gil from Ravorara)\n   - Trade 2 ash for the [Key Item] Pointed jug - (200 gil from Ravorara)\n   - Trade 3 ash for the [Key Item] Cracked club - (300 gil from Ravorara)\n   - Trade 4 ash for the [Key Item] Peeling hairpin - (400 gil from Ravorara)\n6. After getting the 4 key items, return to Port Bastok and talk to Ravorara four (4) times, once for each key item. You will see a cutscene and receive gil for each key item, as listed above.\n7. Return to Oldton Movalpolos and trade the final/11th ash to Brakobrik at (K-11), but choose "No Thanks" when he offers to give you something in return. He\'ll give you the [Key Item] Old nametag.\n8. Return to Port Bastok and talk with Ravorara for another cutscene.\n9. Go to Bastok Mines and talk with Pavvke in his residence on the lower level (I-7) for a cutscene, completing the quest and receiving your reward.',
        notes = nil,
    },
