    ['The Curse Collector'] = {
        id = 34,
        start_npc = 'Zon-Fobun',
        start_zone = 'Bastok Markets',
        start_pos = 'G-5',
        description = 'Let the magical statues in Beadeaux--the Afflictors and the Mutes--cast their curses on you to capture their spells on Zon-Fobun\'s cursepaper.',
        reward = 'Poison Cesti',
        fame = 'Bastok',
        fame_level = '4',
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Speak with Zon-Fobun to begin quest. You will receive [Key Item]Cursepaper.\n2. Go to Beadeaux and proceed to one of the sets of machines: you need to visit an Afflictor (which Curses whoever comes near it, unless they are currently Silenced) and Mute (which Silences whoever touches it). So it is important to get cursed first, by coming near the Afflictor, and then touch the Mute to become silenced.\n3. The first, and easiest, set of machines: Go straight in when entering Beadeaux, then turn left (go north) when you reach the wall at F-7. Go north to the wall in F-6, then due east to H-6.\n4. From here head south and you\'ll find yourself going into a cave that leads down. Take that down until it exits at H-7 on the lower map. Go west, south, and west again until you near the glowing red Afflictor in G-8. This will curse you, dramatically lowering your maximum HP and MP.\n5. Now head back east and then take your first turn north all the way to G-7 where you will find the Mute. Touch it and you will become silenced, so that you now have both the curses on the Cursepaper.\n6. Return to Zon-Fobun to complete quest.',
        notes = nil,
    },
