    ['The First Meeting'] = {
        id = 52,
        start_npc = 'Oggbi',
        start_zone = 'Port Bastok',
        start_pos = 'E-6',
        description = 'You have been asked to head to Fei\'yin and help Dalzakk, one of Oggbi\'s Students, with his task.',
        reward = 'Temple Gaiters',
        fame = 'Bastok',
        fame_level = '1',
        title = nil,
        repeatable = 'No',
        previous = {'Ghosts of the Past'},
        next = {
            'True Strength',
            'Borghertz\'s Striking Hands',
        },
        requirements = {
            {name = '[Key Item] Letter from Dalzakk', count = 1},
            {name = '[Key Item] San d\'Orian martial arts scroll', count = 1},
        },
        walkthrough = '1. Talk to Oggbi inside the Steaming Sheep Restaurant for a cutscene.\n   - You must be on Monk. Once the Quest is active you can complete it on any job.\n   - You must zone after completing the previous quest.\n2. Travel to Fei\'Yin. Your goal is to zone into, and then out of Qu\'Bia Arena for a cutscene and receive the key item Letter from Dalzakk.\n   - You can use the Home Point warp #1 if you have it.\n3. Travel to Davoi and look for the Hide Flap at (F-7)/(G-7).\n4. When ready click the Hide Flap and pop Deloknok (PLD) and Bilopdop (MNK). Kill them, then search for where the Hide Flap moved to and check for the key item San d\'Orian martial arts scroll.\n   - There is only one Hide Flap and it moves to another random hut in the area after any player searches a hut.  It can appear on any of the huts near (F-7)/(G-7).\n   - If completing this for multiple players, each player on the quest will need to trigger the NMs once before being able to retrieve the key item.\n   - Once the key item is retrieved, there appears to be a cool down of a few minutes before the NMs can be spawned again. Searching a hut during this time period will result in finding nothing without spawning the NMs, and the Hide Flap will move to a new location.\n5. Go back and talk to Oggbi and receive your Temple Gaiters.',
        notes = nil,
    },
    ['The Gustaberg Tour'] = {
        id = 45,
        start_npc = 'Izabele',
        start_zone = 'Metalworks',
        start_pos = 'G-8',
        description = 'You have been asked to form a party with two or more people of level fifteen and below to test Izabele\'s business idea. Your party is to make its way to Drachenfall in North Gustaberg where Hunting Bear, Izabele\'s partner, is waiting.',
        reward = '500g',
        fame = 'Bastok',
        fame_level = '1',
        title = 'Gustaberg Tourist',
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Speak to Izabele to begin quest\n2. Invite at least one other player to form a party of 2. Change to a job that\'s level 15 or below.\n   - Alter egos and fellows do not count toward the requirements.\n   - Level sync does work\n3. Together with your party, travel to North Gustaberg and locate the galka Hunting Bear at F-8 (near waterfalls)\n   - The Survival Guide also puts you at the outpost, which is fairly close to him.\n   - Note any characters under level 20 will have to walk, as mounts require level 20.\n4. Speak with Hunting Bear to complete quest',
        notes = 'Similar to When Wills Collide, Mercenary Camp, and The Kuftal Tour this CS displays fellow party members, a very rare occurrence.\n1. It\'s not much of a different angle than you\'d see in game.\n2. You can watch this CS again with the Goblin Footprint\nOriginally this quest required 6 players and required a level 5 or below job, but was dropped to 2 players and a level 15 or below job with the June 2015 Update\n3. This had an added effect of allowing players who did not have a level 5 or below job to complete the quest with 2008\'s Level Sync functionality, as with the previous level cap, you could not sync due to the minimum level for sync being level 10.\n   - While a silly idea, one could have de-leveled their character to level 5. However, EXP loss on death was removed in the May 2011 update, so only new jobs could give a player access to this if they were leveled above 5.',
    },
