    ['The Siren\'s Tear'] = {
        id = 0,
        start_npc = 'Wahid',
        start_zone = 'Bastok Mines',
        start_pos = 'I-8',
        description = 'Find the Siren\'s Tear for Wahid. This rare gem is known to occasionally appear on the shores of the Gustaberg River. Seek the bard in the Port Bastok restaurant and listen to his story.',
        reward = '150 gil',
        fame = 'Bastok',
        fame_level = '1',
        title = 'Tearjerker',
        repeatable = 'Yes',
        previous = nil,
        next = {'Love and Ice'},
        requirements = {
            {name = 'Siren\'s Tear', count = 1},
        },
        walkthrough = '1. Talk to Wahid (HP #1 Bastok Mines), he will ask for a "Siren\'s Tear".\n2. Travel to J-9 in North Gustaberg and look for a ???. The ??? will appear randomly up and down the length of the river.\n   - Port Bastok HP #1 to North Gustaberg is the quickest way to get to this river\n3. Make sure you have 1 free inventory slot in active bag.\n4. Unequip all weapons and shield in "Main" and "Sub" slot if applicable, then examine the ??? and you will receive the message "... has obtained a Siren\'s Tear".\n5. Go back to Wahid, trade Siren\'s Tear to complete quest.\n6. Can be repeated as many times as you want.',
        notes = nil,
    },
    ['The Stars of Ifrit'] = {
        id = 42,
        start_npc = 'Agapito',
        start_zone = 'Port Bastok',
        start_pos = 'G-6',
        description = 'Agapito wants you to find out the meaning of the following words: "Under a full moon, toward the stars of Ifrit, a bird delivers a letter to the ship in the sky." Also, try to bring back this "letter" to satisfy Agapito\'s curiosity.',
        reward = '2,100 gil',
        fame = 'Bastok',
        fame_level = '3',
        title = 'Star of Ifrit',
        repeatable = nil,
        previous = nil,
        next = {'Love and Ice'},
        requirements = {
            {name = '[Key Item] Airship pass', count = 1},
        },
        walkthrough = '1. You may work on this quest only after you have obtained an [Key Item] Airship pass as its completion requires a trip on the airship.\n2. If you fulfill all the prerequisites of the quest, then speak to Agapito to begin quest.\n3. During a Full Moon at night time, board the San d\'Oria-Jeuno airship.\n   - You can use the /clock on command to check the current moon phase.\n4. Search for an abnormal ??? somewhere on the ship. It will only appear during this very specific time frame.\n5. Touch the ??? to receive the [Key Item] Carrier pigeon letter.\n6. Return to Agapito to complete the quest.',
        notes = nil,
    },
    ['The Talekeeper\'s Gift'] = {
        id = 56,
        start_npc = 'Deidogg',
        start_zone = 'Bastok Mines',
        start_pos = 'H-6',
        description = 'Raogrimm\'s gift to the San d\'Orians was stolen by a band of Goblin thieves from the Behemoth\'s Dominion. The Musketeers are in search of the item, but Deidogg wants you to take it for yourself.',
        reward = 'Fighter\'s Lorica',
        fame = 'Bastok',
        fame_level = '1',
        title = 'Paragon of Warrior Excellence',
        repeatable = 'No',
        previous = {'The Talekeeper\'s Truth'},
        next = nil,
        requirements = {
            {name = 'Ginger Cookie', count = 1},
        },
        walkthrough = '1. You must wait until the next game day after completing The Talekeeper\'s Truth before you can activate this quest.\n2. Speak to Deidogg in Bastok Mines.\n3. Speak to Detzo in Bastok Mines (I-6), located in the alleyway around the corner from Deidogg.(Speak to him again if he mentions a Mythril Sallet)\n4. Obtain a Ginger Cookie (sold by the Curio Moogle, or Valeriano in Port Bastok (K-8)) and trade it to Deidogg. The quest will now be flagged.\n5. Travel to Behemoth\'s Dominion.\n   - If you don\'t have the Survival Guide warp, the quickest way is via Qufim Island; follow the tunnel starting at (G-5) until you zone in.\n6. Proceed to (K-9) in Behemoth\'s Dominion to find a ???.  Touching it will spawn 3 NM goblins:\n   - Doglix Muttsnout (Level 58 WHM)\n   - Moxnix Nightgoggle (Level 58 RNG)\n   - Picklix Longindex (Level 60 THF)\n   - Be aware all 3 NMs will aggressively use Bomb Toss.\n7. Defeat the NMs, and zone out of Behemoth\'s Dominion (back into Qufim Island) to receive a cutscene and your reward.',
        notes = '1. This quest does not get flagged in your log until after you trade the Ginger Cookie to Deidogg.\n2. You can attempt to defeat the mobs on a non-Warrior job (as long as you have the quest).\n3.  The NMs can only be popped once per game day.  Otherwise when touching the ??? you will get the message "It is too blurry to read".',
    },
    ['The Talekeeper\'s Truth'] = {
        id = 55,
        start_npc = 'Phara',
        start_zone = 'Bastok Mines',
        start_pos = 'J-9',
        description = 'Deidogg wants to prove that the\nTalekeeper Raogrimm was no hero.\nFirst, he wants you to defeat the\nQuadav nest guardian in the\nPalborough Mines that Raogrimm\nclaimed to have killed, and take\nfrom it the mottled Quadav egg the\nTailkeeper failed to bring back.',
        reward = 'Fighter\'s Calligae',
        fame = 'Bastok',
        fame_level = '1',
        title = 'none',
        repeatable = 'No',
        previous = {'The Doorman'},
        next = {
            'The Talekeeper\'s Gift',
            'Borghertz\'s Warring Hands',
        },
        requirements = {
            {name = 'Mottled Qdv. Egg', count = 1},
            {name = 'Parasite Skin', count = 1},
        },
        walkthrough = '1. Talk to Phara in Bastok Mines at (J-9).\n2. Talk to Deidogg (H-6) Bastok Mines twice.\n   - He is at the bottom of the ramp that leads to the guild.\n   - After this point the quest can be completed on any job.\n3. Go Palborough Mines and work your way to the top floor. You will find a ??? at (G-10) in a dead end room.\n   - Home Point #1 is very close. If you don\'t have the Home Point, Domenic can also teleport you to Waughroon Shrine which is right next to it.\n4. Examine it to spawn Ni\'Ghu Nestfender. Defeat the NM who will drop a Mottled Quadav Egg.\n   - 3 minute re-spawn.\n5. Return to Bastok and trade the Mottled Quadav Egg to Deidogg.\n   - You can speak to Deidogg again for an additional cutscene.\n6. Go to Castle Oztroja and kill the Yagudo Parasite in the pond on the 3rd floor (H-9) for a Parasite Skin.\n7. Return to Bastok again and trade the Parasite Skin to Deidogg.\n8. Wait a game day (after clock rolls around past 00:00).  Talk to Deidogg for your reward.',
        notes = nil,
    },
    ['The Usual'] = {
        id = 27,
        start_npc = 'Hilda',
        start_zone = 'Port Bastok',
        start_pos = 'E-6',
        description = 'Bring a king truffle to Hilda so she can serve it to an old Steaming Sheep customer.',
        reward = 'Speed Bow',
        fame = 'Bastok',
