        requirements = {
            {name = 'King Truffle', count = 1},
        },
        walkthrough = '1. Speak to Hilda to begin quest.\n2. Trade a King Truffle to Hilda to receive the [Key Item] Steaming Sheep invitation.\n   - Can be found via Auction House, in Voidwatch or dropped from some Funguar enemies in Crawlers\' Nest.\n3. Travel to Metalworks and speak with Raibaht at G-8 (Cid\'s Lab).\n   - Make sure you receive a short dialog pertaining to this specific quest and not a cut-scene for one of the multiple quests that involve Raibaht.\n4. Return to the Steaming Sheep restaurant and speak with Hilda to complete quest.',
