    },
    ['The Walls of Your Mind'] = {
        id = 69,
        start_npc = 'Oggbi',
        start_zone = 'Port Bastok',
        start_pos = 'E-6',
        description = 'Use the cesti granted to you by Master Oggbi to break the barriers that cloud your mind. When you feel the weapon can assist you no further, return to the master for instructions.',
        reward = 'Asuran Fists weapon skill',
        fame = 'Bastok',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. You cannot start this quest if you have another Weapon Skill Quest active. You must return to the person that gave said quest and quit it to start another.\n2. Speaking with Oggbi will grant you the key item Weapon training guide as well as the Knuckles of Trials. You will need to break the latent on the Knuckles of Trials before completing the rest of the quest.\n      - Breaking the Latent\n3. Trade the Knuckles of Trials back to Oggbi. This will give you the key item Map to the Annals of Truth. You will be instructed to travel to the Bostaunieux Oubliette.\n4. Unity NPC warp 122 is available to get you close within Bostaunieux Oubliette well after the drop. Head East and go through connection B to (I-8) where the ??? is located.\n   - Otherwise take Silent Oil with you and head to the Chateau d\'Oraguille. In the entry hall, take the eastern door and follow the path north to Bostaunieux Oubliette.\n   - Once inside the Oubliette, head south to (H-7/8) and then west. Continue west to (E-7/8) and drop down. After you drop, head south again and then turn west. Go west until you have to turn south; repeat this until you come to (F-9) and then turn east.\n   - Follow this path until you come to (I-8), where you will find the ??? to spawn the NM.\n5. This fight is against Bodach, a skeleton. It is weak to Fire and Light attacks. Once you kill it, re-examine the ??? to receive the key item Annals of Truth.\n6. Go back and speak with Oggbi to receive your reward.',
        notes = nil,
    },
    ['The Weight of Your Limits'] = {
        id = 66,
        start_npc = 'Iron Eater',
        start_zone = 'Metalworks',
        start_pos = 'J-8',
        description = 'Use the axe given to you by Iron Eater to test your might. When you feel that you have reached your limits, bring the weapon back to the President\'s Office.',
        reward = 'Steel Cyclone weapon skill',
        fame = 'Bastok',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. You cannot start this quest if you have another Weapon Skill Quest active. You must return to the person that gave said quest and quit it to start another.\n2. Speaking with Iron Eater will grant you the key item Weapon training guide as well as the Axe of Trials. You will need to break the latent on the Axe of Trials before completing the rest of the quest.\n      - Breaking the Latent\n3. Trade the Axe of Trials back to Iron Eater. This will give you the key item Map to the Annals of Truth. You will be instructed to travel to The Sanctuary of Zi\'Tah.\n   - To spawn the NM, use the Survival Guide to zone in The Sanctuary of Zi\'Tah and head to the northwest corner of (F-6) to find the ???.\n   - Alternatively, for the fastest route, use the Unity Warp to Ro\'Maeve (level 125), then zone into The Sanctuary of Zi\'Tah. The ??? is located at (F-5) in the southwest area.\n4. This fight is against Greenman, a treant. It is weak to Fire and Dark attacks. Once you kill it, re-examine the ??? to receive the key item Annals of Truth.\n5. Go back and speak with Iron Eater to receive your reward.',
        notes = nil,
    },
