    ['Too Many Chefs'] = {
        id = 86,
        start_npc = 'Ferghus',
        start_zone = 'Metalworks',
        start_pos = 'G-9',
        description = 'The new apprentice cook is being blamed for everything that goes wrong in the eatery, and today doesn\'t seem to be any different...',
        reward = 'Aileen\'s Delight',
        fame = 'Bastok',
