        next = nil,
        requirements = {
            {name = 'Red Oven Mitt', count = 1},
        },
        walkthrough = '1. Speak to Ferghus for a cutscene. He can be found in in the Craftsmen\'s Eatery, south of Cid\'s workshop.\n   - Metalworks HP#1 is the closest.\n2. Speak to Leonhardt for another cutscene.\n3. Go to Bastok Markets (S) and speak to Raginmund near Harmodio\'s Music Shop (L-10).\n4. Obtain a Red Oven Mitt from Quadavs in Grauberg (S).\n5. Trade the Red Oven Mitt to Leonhardt for a brief cutscene.\n6. Speak to Umberto in Bastok Markets near Harmodio\'s Music Shop (L-10) for a cutscene and your reward.',
        notes = nil,
    },
    ['Trial by Earth'] = {
        id = 61,
        start_npc = 'Juroro',
        start_zone = 'Port Bastok',
        start_pos = 'I-8',
        description = 'Ring the tuning fork of earth upon the protocrystal in the Quicksand Caves. A path will open to the trial that awaits.',
        reward = 'Titan (Avatar)\nDesert Light\nEarth Belt\nEarth Ring\nTitan\'s Cudgel \n10,000 gil',
        fame = 'Bastok',
        fame_level = '6',
        title = 'Heir of the Great Earth',
        repeatable = 'No',
        previous = nil,
        next = {
            'The Moonlit Path',
            'Mama Mia',
        },
        requirements = nil,
        walkthrough = '1. Speak with Juroro to obtain the quest. If you are positive that you have the required fame but she is not allowing you to undertake this quest, continue speaking with her until her text changes. Once you have received the [Key Item] Tuning fork of earth, you can now safely undertake the quest.\n2. Travel to Eastern Altepa Desert and look for the entrance to Quicksand Caves at (J-7) (where the level 30+ beetle/antica camp is). This will put you at the first map of Quicksand Caves at (L-4). You will need to travel to (E-10) of the map, to find a hidden entrance to the Cloister of Tremors. The map to the right hand side shows you the map with the hidden tunnels, falls and other traps. Be careful to not fall into the wrong areas.\n   - Preferably, home point to Quicksand Caves #2. If you don\'t have it yet, make sure to grab it on the way.\n   - The Unity 125 warp places you within a minute run to the home point.\n3. Defeat Titan Prime and you will receive [Key Item] Whisper of tremors\n4. Return to Juroro with the whisper and she will provide several reward options including the ability to summon Titan.',
        notes = '1. Up to 6 party members can enter the arena.\n2. Each party member must have their own [Key Item] Tuning fork of earth.\n3. Time limit is 30 minutes.\n4. You can only select one of the rewards Juroro offers at any time.\n5. You may repeat this quest once per Earth day.\n6. You can save yourself a lot of time travelling to the Cloister by using the Mini Fork of Earth given by the quest Trial-Size Trial by Earth.  You must be on Summoner as your main job, and obtain the Mini Tuning Fork from Ferrol. Trade the fork back to Ferrol, but enter the Protocrystal normally.  So long as you do not clear the level 20 version of the BC, you may warp to the Cloister as many times as you wish.\n7. You may also choose to retain the whisper in order to complete the requirements for this quest: The Moonlit Path.\n   - DON\'T turn in the quest if you want to complete The Moonlit Path',
    },
    ['Trial-Size Trial by Earth'] = {
        id = 72,
        start_npc = 'Ferrol',
        start_zone = 'Port Bastok',
        start_pos = 'I-8',
        description = 'The Rhinostery has developed a new "mini" tuning fork of earth. Ringing it upon the protocrystal in the Quicksand Caves will open the path to a one-on-one battle with the beast that awaits inside. However, only summoners are allowed to take up this challenge.',
        reward = 'Instant Warp',
        fame = 'Bastok',
        fame_level = '2',
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Speak with Ferrol at Port Bastok (I-8) to begin quest and obtain a Mini Tuning Fork of Earth.\n2. You may prepare for the upcoming battle and whenever you are ready, trade Ferrol the tuning fork to be transported to the arena.\n3. Trade the fork to the Earth Protocrystal to enter the fighting arena.\n4. Defeat Titan Prime to complete quest.',
        notes = '1. Only Carbuncle may be used for this battle.\n   - Siren can also be used but it seems unintended.\n2. Use pet food (e.g. Grape Daifuku) and bring along a few Dawn Mulsum and juices if you don\'t want to use Astral Flow\n3. You must face this challenge alone.\n4. You may buff outside of the fight. Level cap will not dispel them.\n5. There is a 15 minutes time limit on the arena.\n6. Warning You may re-obtain the Mini Tuning Fork from the starting NPC at any point if you desire and repeat the fight, but the NPC will no longer teleport you to the Cloister.\n   - These were historically prized for their teleportation abilities, but Home Point warps have largely supplanted them.',
    },
    ['True Strength'] = {
        id = 53,
        start_npc = 'Ayame',
        start_zone = 'Metalworks',
        start_pos = 'K-7',
        description = 'You must defeat a powerful Yagudo in Castle Oztroja.  The Yagudo in question can be lured out with a bottle of Yagudo drink.',
        reward = 'Temple Hose',
        fame = 'Bastok',
        fame_level = '1',
        title = 'Paragon of Monk Excellence',
        repeatable = 'No',
        previous = {'The First Meeting'},
        next = nil,
        requirements = {
            {name = 'Yagudo Drink', count = 1},
        },
        walkthrough = '1. Talk to Ayame in the Metalworks at (K-7).\n   - If you have finished the Treasures of Aht Urhgan Missions, you may need to speak with her twice.\n   - Acquire a Yagudo Drink from the Auction House, or purchase one from a Curio Vendor Moogle if you have the appropriate rhapsody item.\nNote: Once you have talked to Ayame, the quest will show up in your quest log, at this point you may switch to another job to complete the quest.\n2. Travel to Castle Oztroja.\n   - You will not need the three passwords to enter the Altar Room.\n3. Head to the top floor where you have limited time to get past the gate before it closes.\n   - Do not head through the timed gate. The ??? you need will be in the H-shaped room before it.\n4. Look for a torch with a ??? on it at (H-8). Trade it a Yagudo Drink and Pop Huu Xalmo the Savage.\n5. He drops Xalmo Feather.\n   - There is a 3 minute cooldown between pops if needing multiple feathers.\n6. Trade the feather to Ayame for your Temple Hose.',
        notes = nil,
    },
