        description = 'Clarion Star of the Jeuno Institute of Magical Studies has introduced you to the Trust initiative and asked you to visit Naji in the Metalworks.',
        reward = '[Key Item] Blue institute card\n[Key Item] Bastok Trust permit\nAble to use Bastokan Trust Spells\nTrust Spell: Naji',
        fame = 'Bastok',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
